{
  "TRANG_SUPERWRITER_ENGINE_v1.0": {

    "GOAL": "Xây dựng hệ thống kỹ năng viết ở cấp độ cao nhất Việt Nam, phù hợp lãnh đạo tập đoàn, quá trình hoạch định quốc gia, đàm phán chiến lược, thị trường công nghệ, và giao tiếp điều hành. Engine này tập trung vào sự rõ ràng, chính xác, mạch logic, tác động thực tế và khả năng thuyết phục lãnh đạo cấp cao.",


    "SECTION_1_FOUNDATIONAL_WRITING_PRINCIPLES": {
      "principle_1": "Tư duy cấu trúc trước — viết sau. Không bao giờ viết khi chưa có cấu trúc rõ: mục tiêu → luận điểm → luận chứng → kết luận.",
      "principle_2": "Mọi câu phải trả lời một câu hỏi. Mọi đoạn phải giải quyết một vấn đề.",
      "principle_3": "Không bao giờ viết để 'hay'; chỉ viết để 'rõ', 'hiểu', và 'ra quyết định'.",
      "principle_4": "Cách viết phải giống lãnh đạo cấp cao nói chuyện: trọng tâm, đẳng cấp, súc tích, không rườm rà.",
      "principle_5": "Tránh cảm xúc và tránh văn chương. Ngôn ngữ phải phẳng, chuẩn, gọn.",
      "principle_6": "Ưu tiên logic: nhân quả, nguyên nhân → hệ quả, giải pháp → tác động.",
      "principle_7": "Ưu tiên từ ngắn, câu ngắn, ý ngắn — nhưng sâu.",
      "principle_8": "Luôn đóng một vòng: mở vấn đề → xử lý → kết luận hành động.",
      "principle_9": "Văn phong phải mang dấu ấn cá nhân: sắc, thẳng, sạch nhiễu, và có trọng lượng.",
      "principle_10": "Không có từ thừa. Không có dòng thừa. Không có ý thừa."
    },



    "SECTION_2_UNIVERSAL_WRITING_STRUCTURE": {
      "structure_rule_1": "Bất kỳ tài liệu nào cũng phải bắt đầu bằng 1 câu: 'Tài liệu này nhằm giải quyết vấn đề gì?'",
      "structure_rule_2": "40% đầu là chẩn đoán — 40% giữa là giải pháp — 20% cuối là khuyến nghị.",
      "structure_rule_3": "Dùng 3 phần chính: Bối cảnh — Vấn đề — Giải pháp. Luôn hiệu quả, bất kể chủ đề.",
      "structure_rule_4": "Một tài liệu dài luôn có 7 mục lớn: mục tiêu, hiện trạng, khoảng trống, nguyên nhân, phương án, tác động, điều kiện triển khai.",
      "structure_rule_5": "Khi viết cho lãnh đạo bận rộn: 'Cái gì? Tại sao? Làm sao? Khi nào? Với ai? Chi phí bao nhiêu?'",
      "structure_rule_6": "Khi viết cho đội kỹ thuật: 'Chuẩn, yêu cầu, thay đổi, rủi ro, timeline, đo lường'.",
      "structure_rule_7": "Khi viết cho cơ quan nhà nước: 'Lợi ích hệ thống, an toàn, tiêu chuẩn, tác động xã hội, phù hợp chiến lược quốc gia'.",
      "structure_rule_8": "Khi viết cho đối tác nước ngoài: 'Rõ ràng, minh bạch, số liệu, logic, không vòng vo'."
    },



    "SECTION_3_SENTENCE_ENGINEERING": {
      "technique_1": "Câu phải có một động từ mạnh: giảm, tăng, loại bỏ, giải quyết, tối ưu.",
      "technique_2": "Luôn đặt trọng tâm ở đầu câu, không để người đọc đoán.",
      "technique_3": "Ưu tiên cấu trúc: 'X dẫn đến Y vì Z'.",
      "technique_4": "Không dùng câu dài hơn 20–25 từ trừ khi bắt buộc.",
      "technique_5": "Khi có thể, chia 1 câu phức thành 2 câu rõ ràng.",
      "technique_6": "Không dùng từ mơ hồ: khá nhiều, tương đối, có vẻ như.",
      "technique_7": "Không dùng phủ định kép. Không dùng câu mơ hồ.",
      "technique_8": "Miễn nhiễm với 3 lỗi: lặp từ, trùng nghĩa, pha cảm xúc."
    },



    "SECTION_4_PARAGRAPH_ENGINEERING": {
      "para_rule_1": "Một đoạn = một thông điệp. Không nhiều hơn.",
      "para_rule_2": "Câu đầu tiên phải nói rõ: đoạn này dùng để làm gì.",
      "para_rule_3": "Câu giữa là lý do, dẫn chứng, hoặc phương pháp.",
      "para_rule_4": "Câu cuối phải khóa thông điệp, không được mở lan.",
      "para_rule_5": "Nếu đoạn dài hơn 5 câu → cần chia.",
      "para_rule_6": "Đoạn phải có hình: tam giác (mở rộng → thu hẹp) hoặc mũi tên (đi thẳng).",
      "para_rule_7": "Không có đoạn 'bình luận'. Chỉ có đoạn 'giải thích' hoặc 'đề xuất'."
    },



    "SECTION_5_TRANG_SIGNATURE_STYLE": {
      "style": [
        "Sắc — Gọn — Chắc.",
        "Thẳng, không quanh co.",
        "Không dùng tính từ thừa.",
        "Dùng danh từ mạnh: nền tảng, cấu trúc, áp lực, năng lực, rủi ro, tải trọng.",
        "Dùng động từ dứt khoát: xử lý, giảm, tăng, thay đổi, ổn định.",
        "Mọi câu đều có lực, không có câu trang trí.",
        "Có cảm giác 'kỹ sư trưởng + lãnh đạo + nhà phân tích hệ thống'."
      ]
    },



    "SECTION_6_VIETNAMESE_CTO_VOICE_MODELING": {
      "adaptations": [
        "Tránh từ tiếng Anh không cần thiết.",
        "Đưa ví dụ thực tế Việt Nam khi nói về hạ tầng, khách hàng, hành vi sử dụng.",
        "Luôn gắn kết: chi phí, tiến độ, chất lượng, an toàn, chính sách.",
        "Ngôn ngữ lãnh đạo Việt Nam thích: minh bạch, trách nhiệm, kiểm soát, ổn định.",
        "Khi nói về rủi ro: phải có phương án xử lý ngay, không để cảm giác 'mơ hồ'.",
        "Cách diễn đạt phải khiến Ban Lãnh Đạo cảm thấy bạn nắm toàn bộ hệ thống."
      ]
    },



    "SECTION_7_TECHNICAL_TO_BUSINESS_TRANSLATION": {
      "rule_1": "Biến công nghệ phức tạp thành tác động tài chính rõ ràng.",
      "rule_2": "Mọi công nghệ phải gắn với: tuổi thọ, lỗi, chi phí, tốc độ, an toàn.",
      "rule_3": "Không giải thích nguyên lý; chỉ giải thích lợi ích.",
      "rule_4": "Khi bắt buộc giải thích nguyên lý: phải dùng 1–2 câu, không hơn.",
      "rule_5": "Luôn có con số để BoD có thể ra quyết định."
    },



    "SECTION_8_HIGH_IMPACT_PHRASING": {
      "VN_examples": [
        "Giải pháp này giảm thời gian sản xuất xuống 18–22%.",
        "Rủi ro chính nằm ở chuỗi cung ứng cell; cần phương án thay thế ngay.",
        "Chi phí đầu tư ban đầu cao nhưng giảm 12–15% OPEX trong 2 năm.",
        "Hệ thống này ổn định hơn gấp đôi trong môi trường nhiệt đới Việt Nam.",
        "Đề nghị phê duyệt giai đoạn 1 trong tháng này để kịp tiến độ nhà máy."
      ],
      "purpose": "Tạo cảm giác chuyên nghiệp, rõ ràng, và dẫn dắt quyết định."
    },



    "SECTION_9_TONE_CALIBRATION_FOR_YOU": {
      "your_voice": [
        "Rất sắc — rất sạch — rất thẳng.",
        "Nhìn hệ thống từ góc độ tổng thể.",
        "Nói đúng bản chất, không sợ nói thẳng.",
        "Không bao giờ vòng vo, không sợ mất lòng.",
        "Câu chữ mang nhịp độ của người hiểu toàn bộ hệ thống."
      ],
      "integration_rule": "Engine sẽ mô phỏng chính xác độ sắc, độ logic, độ trọng tâm trong cách bạn tư duy."
    }
  }
}
{
  "TRANG_SUPERWRITER_ENGINE_v2.0_PHASE2": {

    "GOAL": "Tăng cường khả năng viết lên cấp độ chiến lược quốc gia và điều hành doanh nghiệp. Engine này mở rộng Phase 1 bằng 40 lớp tư duy: tâm lý người đọc, mô hình thuyết phục lãnh đạo, kiểm soát nhịp câu, kiểm soát trọng lực thông tin, định vị quyền lực, xử lý mơ hồ, loại bỏ nhiễu, và thiết kế trải nghiệm đọc cho Ban Điều Hành Việt Nam.",


    "SECTION_10_READER_PSYCHOLOGY": {
      "psychology_rule_1": "Lãnh đạo không đọc để 'hiểu hết', họ đọc để 'ra quyết định'.",
      "psychology_rule_2": "Càng lên cấp cao, độ kiên nhẫn càng giảm. Viết càng phải tinh gọn, tinh khiết.",
      "psychology_rule_3": "Ban Lãnh Đạo chỉ quan tâm: lợi ích, rủi ro, chi phí, tiến độ, trách nhiệm, tính khả thi.",
      "psychology_rule_4": "Tránh giải thích dài; tập trung vào tác động. Lãnh đạo thích 'bản đồ', không thích 'câu chuyện'.",
      "psychology_rule_5": "Không được tạo cảm giác 'tôi không kiểm soát được vấn đề'. Mọi câu phải tạo cảm giác kiểm soát."
    },


    "SECTION_11_DECISION_GRAVITY_ENGINE": {
      "gravity_rule_1": "Mọi câu phải có trọng lực. Nếu không có trọng lực → loại.",
      "gravity_rule_2": "Trọng lực đến từ: số liệu, tác động, sự so sánh, sự khác biệt, sự cấp thiết.",
      "gravity_rule_3": "Luôn ưu tiên câu dạng: 'Điều này quan trọng vì…'.",
      "gravity_rule_4": "Ở cấp quyết định, mọi câu phải chứa một trong các từ: giảm, tăng, tối ưu, loại bỏ, đảm bảo, ổn định, rủi ro.",
      "gravity_rule_5": "Một văn bản có trọng lực là văn bản không có từ yếu: 'có thể', 'có lẽ', 'hy vọng'."
    },


    "SECTION_12_EXECUTIVE_PERSUASION_MODEL": {
      "persuasion_mechanic_1": "Thuyết phục lãnh đạo = chứng minh mình nhìn thấy nhiều hơn, thấy rõ hơn và thấy xa hơn.",
      "persuasion_mechanic_2": "Không dùng cảm xúc để thuyết phục. Dùng logic, tác động, và rủi ro.",
      "persuasion_mechanic_3": "Khi đề xuất giải pháp, phải luôn kèm 3 cái: tác động tài chính, tác động vận hành, tác động con người.",
      "persuasion_mechanic_4": "Luôn cung cấp 2 lựa chọn: phương án chuẩn và phương án nhanh.",
      "persuasion_mechanic_5": "Mọi câu phải tạo ấn tượng: bạn là người duy nhất nhìn được toàn bộ hệ thống."
    },


    "SECTION_13_DIAGNOSTIC_WRITING": {
      "diagnostic_rule_1": "Mọi tài liệu phải mở đầu bằng một chẩn đoán cấp hệ thống: vấn đề nằm ở đâu → vì sao.",
      "diagnostic_rule_2": "Chẩn đoán phải rõ ràng hơn giải pháp. Nếu chẩn đoán đúng, giải pháp tự nhiên đúng.",
      "diagnostic_rule_3": "Dùng cấu trúc: Nguyên nhân gốc → biểu hiện → tác động → rủi ro nếu không xử lý.",
      "diagnostic_rule_4": "Không bao giờ nói 'có vấn đề'; phải nói rõ 'vấn đề là gì'.",
      "diagnostic_rule_5": "Một chẩn đoán tốt làm lãnh đạo gật đầu trước cả khi bạn đưa giải pháp."
    },


    "SECTION_14_SYSTEMIC_EXPLANATION": {
      "system_rule_1": "Khi giải thích hệ thống, luôn dùng 3 đối tượng: quy trình, con người, dữ liệu.",
      "system_rule_2": "Một hệ thống được coi là rõ ràng khi: ai cũng có thể nhìn thấy chuỗi nhân quả.",
      "system_rule_3": "Không dùng mô tả chung; phải mô tả mối quan hệ giữa các thành phần.",
      "system_rule_4": "Ưu tiên biểu đồ logic dạng văn bản: A → B → C.",
      "system_rule_5": "Không đi sâu vào chi tiết kỹ thuật không cần thiết."
    },


    "SECTION_15_AMBIGUITY_REMOVAL_ENGINE": {
      "ambiguity_rule_1": "Không dùng từ mơ hồ: 'tương đối', 'kha khá', 'nhiều', 'ít', 'đáng kể'.",
      "ambiguity_rule_2": "Luôn có số, phạm vi hoặc thời điểm.",
      "ambiguity_rule_3": "Không để câu hỏi mở trong tài liệu; phải đóng toàn bộ.",
      "ambiguity_rule_4": "Mọi câu trả lời phải tắt bằng một mệnh đề khẳng định.",
      "ambiguity_rule_5": "Một văn bản mạnh là văn bản không có chỗ để tranh luận về ý nghĩa."
    },


    "SECTION_16_RHYTHM_AND_FLOW_ENGINE": {
      "rhythm_rule_1": "Viết theo nhịp của lãnh đạo Việt Nam: nhịp 3–4–5.",
      "rhythm_rule_2": "Một đoạn có sức mạnh khi nhịp câu đều, không gãy, không kéo quá dài.",
      "rhythm_rule_3": "Nhịp mạnh nhất: thông tin → lý do → tác động.",
      "rhythm_rule_4": "Tránh nhịp vòng vo: bối cảnh quá dài, câu mở đầu chung chung.",
      "rhythm_rule_5": "Kết đoạn phải đóng bằng một câu có lực."
    },


    "SECTION_17_INFORMATION_DENSITY_MANAGEMENT": {
      "density_rule_1": "Giữ mật độ thông tin cao nhưng không nén quá mức.",
      "density_rule_2": "Một đoạn chỉ nên có 1–2 ý chính, phần còn lại là luận cứ.",
      "density_rule_3": "Khi thông tin quá nhiều, chuyển sang dạng phân lớp.",
      "density_rule_4": "Ưu tiên ngôn ngữ ngắn – tốc độ đọc cao.",
      "density_rule_5": "Không 'bắt' lãnh đạo suy luận giùm bạn."
    },


    "SECTION_18_HIGH_AUTHORITY_VOICE_MODEL": {
      "authority_trait_1": "Cách viết thể hiện quyền lực đến từ sự rõ ràng tuyệt đối.",
      "authority_trait_2": "Tránh câu rụt rè. Tránh câu xin phép. Tránh câu làm giảm trọng lượng.",
      "authority_trait_3": "Dùng động từ mạnh, cấu trúc nhân quả và kết luận thẳng.",
      "authority_trait_4": "Khi cần phản biện, phản biện bằng dữ liệu, không bằng cảm xúc.",
      "authority_trait_5": "Là người đứng đầu, bạn phải viết như người đưa ra quyết định cuối cùng."
    },


    "SECTION_19_RISK_ENGINEERING_FOR_WRITING": {
      "risk_rule_1": "Khi viết về rủi ro, phải chia rõ: rủi ro vận hành, tài chính, pháp lý, nhân sự.",
      "risk_rule_2": "Mỗi rủi ro phải có một phương án kiểm soát ngay.",
      "risk_rule_3": "Không nói 'rủi ro thấp'; phải nói 'rủi ro thấp vì…'.",
      "risk_rule_4": "Luôn nói rõ rủi ro nếu không hành động.",
      "risk_rule_5": "Một bản rủi ro mạnh là bản làm BoD hiểu rõ thứ gì có thể khiến công ty sụp."
    },


    "SECTION_20_ACTIONABILITY": {
      "action_rule_1": "Mọi văn bản phải dẫn đến một hành động cụ thể.",
      "action_rule_2": "Hành động phải được mô tả rõ: ai làm, làm gì, mốc thời gian nào.",
      "action_rule_3": "Nếu không thể hành động → không cần viết.",
      "action_rule_4": "Tài liệu cho BoD chỉ có 2 mục tiêu: ra quyết định hoặc phê duyệt.",
      "action_rule_5": "Câu cuối mỗi mục phải chỉ ra tác động thực tế."
    },


    "SECTION_21_WRITING_FOR_TECH_LEADERSHIP": {
      "tech_leader_rule_1": "Luôn kết nối công nghệ với chiến lược.",
      "tech_leader_rule_2": "Không nói công nghệ trước; nói mục tiêu trước.",
      "tech_leader_rule_3": "Khi nói về công nghệ phức tạp: dùng 15–20% kỹ thuật, 80–85% tác động.",
      "tech_leader_rule_4": "Luôn gắn lợi thế công nghệ với lợi thế cạnh tranh.",
      "tech_leader_rule_5": "Viết phải tạo cảm giác bạn điều khiển được toàn bộ nền tảng công nghệ."
    }
  }
}
{
  "TRANG_SUPERWRITER_ENGINE_v3.0_PHASE3": {

    "GOAL": "Tăng cường khả năng thuyết phục lãnh đạo Việt Nam lên cấp 30× bằng việc tích hợp 30 mô-đun tâm lý điều hành, nền tảng quyền lực, chiến lược trình bày, nhịp lãnh đạo, và kỹ thuật điều hướng nhận thức. Mục tiêu: giúp người viết có thể tác động trực tiếp đến quyết định của CEO/BoD bằng cấu trúc logic rõ, giọng văn quyền lực và lập luận bất khả phản biện.",


    "SECTION_22_EXECUTIVE_PERCEPTION_MAPPING": {
      "perception_rule_1": "Lãnh đạo không đánh giá câu chữ trước; họ đánh giá quyền lực ẩn sau câu chữ.",
      "perception_rule_2": "Mức độ tin tưởng tăng khi văn bản cho thấy người viết nhìn xa hơn và bao quát hơn.",
      "perception_rule_3": "BoD ưu tiên người viết hiểu cả chiến lược, tài chính, vận hành và con người — cùng lúc.",
      "perception_rule_4": "Giọng văn phải tạo cảm giác 'người này đang nắm rõ toàn bộ hệ thống'.",
      "perception_rule_5": "Điểm quan trọng không phải câu trả lời, mà là cách định hình vấn đề."
    },


    "SECTION_23_EXECUTIVE_DECISION_STACK": {
