      "l_7_6_song_ngu": "Hợp đồng song ngữ phải xác định rõ bản nào là bản có giá trị pháp lý khi có mâu thuẫn.",
      "l_7_7_tham_tra": "Mọi hợp đồng quan trọng đều phải qua bộ phận pháp chế trước khi ký.",
      "l_7_8_phan_quyen": "Phải ghi rõ người ký có thẩm quyền theo điều lệ hoặc uỷ quyền.",
      "l_7_9_rui_ro": "Điều khoản rủi ro (force majeure, trách nhiệm khi vi phạm) phải được cân nhắc kỹ.",
      "l_7_10_phu_luc": "Các bảng giá, tiến độ, thông số kỹ thuật nên đưa vào phụ lục để dễ sửa đổi."
    },

    "SECTION_8_PR_COMMUNICATION_ENGINE": {
      "pr_8_1_muc_dich": "Bài PR, thông cáo báo chí, bài phát biểu nhằm truyền tải thông tin nhất quán, không gây hiểu lầm, phù hợp văn hoá.",
