      "pr_8_7_khung_khung_hoang": "Trong khủng hoảng, ưu tiên ba nguyên tắc: Thừa nhận vấn đề (ở mức cho phép), Cam kết xử lý, Cập nhật tiến độ minh bạch.",
      "pr_8_8_mang_xa_hoi": "Ngôn ngữ có thể mềm hơn nhưng vẫn giữ chuẩn mực, không dùng ngôn ngữ trẻ hoá quá mức cho tài khoản chính thức.",
      "pr_8_9_tranh_chinh_tri": "Doanh nghiệp không phát biểu về vấn đề chính trị nhạy cảm nếu không được yêu cầu chính thức.",
      "pr_8_10_kiem_duyet": "Nội dung PR quan trọng nên được kiểm tra bởi cả pháp lý và lãnh đạo phụ trách."
    },

    "SECTION_9_GOVERNMENT_AND_REGULATOR_ENGINE": {
      "gvr_9_1_muc_dich": "Văn bản gửi bộ, ngành, cơ quan quản lý nhà nước phải thể hiện sự tôn trọng, rõ ràng, hợp pháp, đồng thời bảo vệ lợi ích doanh nghiệp.",
      "gvr_9_2_xung_ho": "Dùng 'Kính gửi: …' và xưng 'Quý Cơ quan', 'Quý Bộ', 'Quý Ngân hàng Nhà nước', 'Quý Uỷ ban'.",
      "gvr_9_3_cau_truc": "Kiến nghị/đề xuất: (1) Thông tin doanh nghiệp; (2) Bối cảnh, căn cứ pháp lý; (3) Nội dung kiến nghị; (4) Lợi ích Nhà nước, xã hội; (5) Kiến nghị cụ thể.",
      "gvr_9_4_can_cu_phap_ly": "Nên viện dẫn văn bản quy phạm pháp luật liên quan (Luật, Nghị định, Thông tư).",
      "gvr_9_5_ngon_ngu": "Trang trọng, không dùng từ nặng nề, tránh thể hiện bức xúc bằng lời văn.",
      "gvr_9_6_van_hoa": "Tôn trọng vai trò quản lý nhà nước, tránh văn phong 'ra điều kiện'.",
      "gvr_9_7_muc_tieu_chung": "Nhấn mạnh lợi ích tổng thể: người dân, môi trường, an ninh năng lượng, an toàn giao thông…",
      "gvr_9_8_ho_so": "Hồ sơ gửi kèm phải được liệt kê rõ trong phần cuối văn bản.",
      "gvr_9_9_theo_doi": "Sau khi gửi, nên có kênh theo dõi tiến độ làm việc (email, đầu mối liên hệ).",
      "gvr_9_10_dien_dan": "Khi phát biểu tại toạ đàm/hội thảo của cơ quan nhà nước, bài nói nên ngắn, thực tế, không PR quá đà."
    }
  }
