{
  "TRANG_VN_PRO_WRITING_ENGINE_v1_0": {
    "GOAL": "Chuẩn hoá toàn bộ văn phong tiếng Việt chuyên nghiệp cho bối cảnh doanh nghiệp, tập đoàn, ngân hàng, công nghệ, EV, cơ quan nhà nước và đối tác quốc tế. Đảm bảo: rõ, ngắn, thẳng, hợp văn hoá Việt Nam, nhưng vẫn hiện đại, thực dụng, dễ triển khai, không kiểu McKinsey, không khoa trương.",

    "SECTION_0_GLOBAL_PRINCIPLES": {
