      "g_0_4_ton_trong_thang_cap": "Giữ ngôn ngữ tôn trọng cấp trên, nhưng không rào trước đón sau quá mức.",
      "g_0_5_tranh_my_tu": "Hạn chế tối đa tính từ và trạng từ không cần thiết.",
      "g_0_6_khong_ngoac_kep": "Hạn chế dùng ngoặc kép để nhấn mạnh; chỉ dùng khi trích dẫn chính thức.",
      "g_0_7_truc_dien": "Đề xuất, kiến nghị, cảnh báo nêu trực diện, không nói vòng.",
      "g_0_8_kiem_soat_tone": "Không dùng từ tiêu cực, công kích cá nhân; chỉ nói về hệ thống, quy trình, kết quả.",
      "g_0_9_ngon_ngu_thuan_viet": "Ưu tiên từ thuần Việt, chỉ dùng thuật ngữ tiếng Anh khi cần thiết và có chú thích.",
      "g_0_10_chong_mo_ho": "Mọi câu chứa 'cần', 'nên', 'xem xét' phải đi kèm chủ thể và thời hạn cụ thể."
    },

    "SECTION_1_COMMON_STYLE_RULES": {
      "c_1_1_ngu_canh": "Xác định rõ đối tượng nhận: nội bộ, HĐQT, đối tác, cơ quan quản lý, khách hàng.",
      "c_1_2_xung_ho": "Dùng cách xưng hô theo vị trí: 'Kính gửi', 'Thưa', 'Anh/Chị', 'Quý Ông/Bà', 'Quý Cơ quan'. Không dùng 'bạn', 'mọi người' trong văn bản chính thức.",
      "c_1_3_cau_truc_chung": "Cấu trúc chung: Mục đích → Bối cảnh ngắn gọn → Nội dung chính → Đề xuất / Kiến nghị → Hành động / Tiếp theo.",
