    "SECTION_7_CONTRACT_AND_LEGAL_WRITING_ENGINE": {
      "l_7_1_muc_dich": "Soạn thảo hợp đồng và văn bản pháp lý nhằm bảo vệ quyền lợi và giảm rủi ro pháp lý.",
      "l_7_2_ngon_ngu": "Ngôn ngữ phải chặt chẽ, đồng nhất, tránh từ đồng nghĩa gây tranh cãi.",
      "l_7_3_dinh_nghia": "Các thuật ngữ chính nên được định nghĩa ở Điều 1.",
